{
  "layout": "timeline",
  "title": "推广模式",
  "events": [
    {
      "date": "0-3个月",
      "title": "灯塔验证",
      "description": "聚焦中航光电、北方兵器研究所等已验证标杆客户，深度匹配其核心痛点，定制“硬件+虚拟场景+量化评估”最小可行方案。通过3个月试点交付可感知价值（培训周期缩短40%、耗材损耗下降90%），系统沉淀《航空装配实训白皮书》《国防维修训练应用报告》及标准化销售工具包，固化“需求诊断-方案验证-价值量化-案例转化”全流程SOP，为规模化复制提供实证模板与信任基石。"
    },
    {
      "date": "3-6个月",
      "title": "生态筑基",
      "description": "深度绑定哈尔滨工业大学智能人机交互研究中心及校企合作平台，将灯塔案例转化为“哈工大-龙影”联合品牌资产。策划“虚实协同·高端制造实训产教对接会”，定向邀请东北地区制造企业、职业院校关键决策人参与，精准获取50+高质量潜在客户线索。同步建立产教融合基地与季度技术沙龙机制，将院校资源转化为长效推荐渠道与生态合作枢纽，3个月内完成首轮商务对接，目标转化率30%。"
    },
    {
      "date": "0-12个月",
      "title": "分阶推广：行业深耕期",
      "description": "聚焦航空、国防细分领域，通过行业垂直媒体深度解读灯塔案例，参与“中国国际工业博览会”等权威展会，强化专业影响力，目标签约5家头部客户。"
    },
    {
      "date": "12-24个月",
      "title": "分阶推广：区域拓展期",
      "description": "依托哈工大区域辐射力，联合中国一重、哈电集团等共建3个东北区域实训示范点，以“技术展示+本地化服务”模式实现区域市场渗透。"
    },
    {
      "date": "24个月后",
      "title": "分阶推广：全国复制期",
      "description": "提炼标准化推广包，结合线上技术直播、行业白皮书精准投放，同步拓展轨道交通、能源装备等新行业，通过全国性峰会实现跨域复制，构建“标杆引领-区域扎根-生态辐射”的可持续增长体系。"
    }
  ]
}

